#!/usr/bin/env python3
"""
Simple Shell Implementation - Demonstrates CLI concepts
This is an educational shell that shows how command interpreters work
"""

import os
import sys
import subprocess
from pathlib import Path

# Dictionary of built-in commands (Approach 1: shell contains the code)
BUILTIN_COMMANDS = {
 'help': 'Show available commands',
 'pwd': 'Print working directory',
 'cd': 'Change directory (usage: cd <path>)',
 'echo': 'Print text to screen',
 'list': 'List files in current directory',
 'clear': 'Clear the screen',
 'exit': 'Exit the shell'
}

def parse_command(user_input):
 """Parse user input into command and arguments"""
 parts = user_input.strip().split()
 if not parts:
 return None, []
 return parts[0], parts[1:]

def execute_builtin(command, args):
 """Execute built-in commands (Approach 1)"""
 if command == 'help':
 print("Available commands:")
 for cmd, desc in BUILTIN_COMMANDS.items():
 print(f" {cmd:10} - {desc}")

 elif command == 'pwd':
 print(os.getcwd())

 elif command == 'cd':
 if not args:
 # cd without arguments goes to home directory
 os.chdir(os.path.expanduser('~'))
 else:
 try:
 os.chdir(args[0])
 except FileNotFoundError:
 print(f"cd: {args[0]}: No such directory")
 except Exception as e:
 print(f"cd: error: {e}")

 elif command == 'echo':
 print(' '.join(args))

 elif command == 'list':
 # List files with simple formatting
 path = Path('.')
 for item in sorted(path.iterdir()):
 prefix = 'd' if item.is_dir() else '-'
 print(f"{prefix} {item.name}")

 elif command == 'clear':
 os.system('cls' if os.name == 'nt' else 'clear')

 else:
 return False # Not a builtin
 return True

def find_external_command(command_name):
 """Search for external command in system PATH (Approach 2)"""
 # Search in current directory first
 if os.path.isfile(command_name):
 return command_name

 # Search in PATH directories
 path_dirs = os.environ.get('PATH', '').split(os.pathsep)
 for directory in path_dirs:
 command_path = os.path.join(directory, command_name)
 # Add common extensions for Windows
 for ext in ['', '.exe', '.bat', '.cmd']:
 if os.path.isfile(command_path + ext):
 return command_path + ext
 return None

def execute_external(command, args):
 """Execute external command using system programs (UNIX Approach 2)"""
 command_path = find_external_command(command)

 if command_path is None:
 print(f"Command not found: {command}")
 return

 try:
 # Execute the external program
 # This simulates: fork() + exec() in UNIX
 result = subprocess.run(
 [command_path] + args,
 capture_output=True,
 text=True
 )
 if result.stdout:
 print(result.stdout, end='')
 if result.stderr:
 print(result.stderr, end='', file=sys.stderr)
 except PermissionError:
 print(f"Permission denied: {command}")
 except Exception as e:
 print(f"Error executing {command}: {e}")

def run_shell():
 """Main shell loop"""
 print("=" * 50)
 print(" Simple Shell - Educational Implementation")
 print(" Type 'help' for available commands")
 print(" Type 'exit' to quit")
 print("=" * 50)

 while True:
 try:
 # Display prompt with current directory
 cwd = os.getcwd().split(os.sep)[-1] or os.sep
 user_input = input(f"{cwd}$ ").strip()

 # Parse command
 command, args = parse_command(user_input)

 if command is None:
 continue

 # Check for exit
 if command == 'exit':
 print("Goodbye!")
 break

 # Try built-in commands first
 if execute_builtin(command, args):
 continue

 # Otherwise, try external command (UNIX approach)
 execute_external(command, args)

 except KeyboardInterrupt:
 print("\nUse 'exit' to quit the shell")
 except EOFError:
 print("\nGoodbye!")
 break

if __name__ == "__main__":
 run_shell()

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <string.h>
#include <fcntl.h>

/*
 * System Calls Demonstration
 * This program shows how programs interact with the OS through system calls
 * 
 * Key System Calls demonstrated:
 * - fork() : Create a new process
 * - exec() : Replace current process with new program 
 * - wait() : Wait for child process to complete
 * - open() : Open files
 * - write() : Write to file descriptors
 * - close() : Close file descriptors
 * - getpid() : Get process ID
 * - getcwd() : Get current working directory
 */

void demonstrate_process_calls() {
 printf("\n=== Process Management System Calls ===\n");

 pid_t pid = fork();

 if (pid < 0) {
 // Error occurred
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 else if (pid == 0) {
 // Child process
 printf("Child Process: PID = %d, Parent PID = %d\n", 
 getpid(), getppid());

 // Demonstrate exec() - replace this process with 'ls' command
 char *args[] = {"ls", "-la", NULL};
 printf("Child: Executing 'ls -la' using exec()...\n");
 execvp("ls", args);

 // If exec returns, an error occurred
 perror("exec failed");
 exit(EXIT_FAILURE);
 }
 else {
 // Parent process
 printf("Parent Process: PID = %d, Child PID = %d\n", 
 getpid(), pid);

 // Wait for child to complete
 int status;
 waitpid(pid, &status, 0);

 if (WIFEXITED(status)) {
 printf("Child exited with status: %d\n", 
 WEXITSTATUS(status));
 }
 }
}

void demonstrate_file_calls() {
 printf("\n=== File Management System Calls ===\n");

 // Create and write to a file using system calls
 int fd = open("demo_output.txt", O_WRONLY | O_CREAT | O_TRUNC, 0644);

 if (fd < 0) {
 perror("open failed");
 return;
 }

 printf("File opened successfully, descriptor: %d\n", fd);

 // Write data using write() system call
 char *message = "Hello from System Calls!\nThis demonstrates file I/O.\n";
 ssize_t bytes_written = write(fd, message, strlen(message));

 printf("Wrote %zd bytes to file\n", bytes_written);

 // Close the file
 close(fd);
 printf("File closed\n");

 // Read back the file
 fd = open("demo_output.txt", O_RDONLY);
 if (fd >= 0) {
 char buffer[256];
 ssize_t bytes_read = read(fd, buffer, sizeof(buffer) - 1);
 buffer[bytes_read] = '\0';
 printf("Read from file: %s", buffer);
 close(fd);
 }
}

void demonstrate_info_calls() {
 printf("\n=== Information System Calls ===\n");

 // Get current working directory
 char cwd[1024];
 if (getcwd(cwd, sizeof(cwd)) != NULL) {
 printf("Current directory: %s\n", cwd);
 }

 // Get process information
 printf("Current process ID: %d\n", getpid());
 printf("Parent process ID: %d\n", getppid());

 // Get user ID
 printf("Real user ID: %d\n", getuid());
}

void demonstrate_cli_features() {
 printf("\n=== CLI Features Demonstration ===\n");

 // Demonstrate piping concept using pipe() system call
 int pipefd[2];

 if (pipe(pipefd) == -1) {
 perror("pipe failed");
 return;
 }

 printf("Created pipe: readfd=%d, writefd=%d\n", 
 pipefd[0], pipefd[1]);

 // Write to pipe
 char *data = "Data flowing through pipe!\n";
 write(pipefd[1], data, strlen(data));

 // Read from pipe
 char buffer[256];
 ssize_t n = read(pipefd[0], buffer, sizeof(buffer) - 1);
 buffer[n] = '\0';
 printf("Read from pipe: %s", buffer);

 close(pipefd[0]);
 close(pipefd[1]);
}

int main() {
 printf("========================================\n");
 printf(" System Calls Demonstration\n");
 printf(" Showing how programs interact with OS\n");
 printf("========================================\n");

 demonstrate_info_calls();
 demonstrate_file_calls();
 demonstrate_process_calls();
 demonstrate_cli_features();

 printf("\n=== Demonstration Complete ===\n");

 return 0;
}
